// Attack: passing string longer than 50 chars
// overflows into return address

// SECURE CODE - Using safe functions
#include <stdio.h>
#include <string.h>

void process_user_input(char *user_input) {
    char buffer[50];
    errno_t err;

    // Safe version with explicit size
    err = strcpy_s(buffer, sizeof(buffer), user_input);

    if (err != 0) {
        printf("Error: Input too long\n");
        return;
    }
    printf("Input: %s\n", buffer);
}

